import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import io from 'socket.io-client';
import './ChatBot.css';

const ChatBot = () => {
  const { user, isAuthenticated } = useAuth();
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [socket, setSocket] = useState(null);
  const [isConnected, setIsConnected] = useState(false);
  const messagesEndRef = useRef(null);
  const typingTimeoutRef = useRef(null);

  useEffect(() => {
    // Connect to Socket.io server
    const newSocket = io('http://localhost:5000');
    setSocket(newSocket);

    newSocket.on('connect', () => {
      console.log('Connected to chat server');
      setIsConnected(true);
      
      // Join user's personal room
      if (user) {
        newSocket.emit('join-room', `user-${user._id}`);
      }
    });

    newSocket.on('disconnect', () => {
      console.log('Disconnected from chat server');
      setIsConnected(false);
    });

    newSocket.on('receive-message', (data) => {
      setMessages(prev => [...prev, {
        text: data.message,
        sender: data.sender,
        timestamp: new Date(data.timestamp),
        isOwn: false
      }]);
      setIsTyping(false);
    });

    newSocket.on('user-typing', (data) => {
      setIsTyping(data.isTyping);
    });

    // Initial welcome messages
    setTimeout(() => {
      setMessages([
        {
          text: "👋 Welcome to Real Estate! How can we help you today?",
          sender: 'bot',
          timestamp: new Date(),
          isOwn: false
        },
        {
          text: "I'm here to assist you with finding your dream property!",
          sender: 'bot',
          timestamp: new Date(),
          isOwn: false
        }
      ]);
    }, 1000);

    return () => {
      newSocket.close();
    };
  }, [user]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleSendMessage = (e) => {
    e.preventDefault();
    
    if (!inputMessage.trim()) return;

    if (!isAuthenticated) {
      alert('Please login to chat with us!');
      return;
    }

    const newMessage = {
      text: inputMessage,
      sender: user.name,
      timestamp: new Date(),
      isOwn: true
    };

    setMessages(prev => [...prev, newMessage]);

    // Send to server
    if (socket && isConnected) {
      socket.emit('send-message', {
        roomId: `user-${user._id}`,
        message: inputMessage,
        sender: user.name
      });
    }

    setInputMessage('');

    // Simulate agent response
    setTimeout(() => {
      const responses = [
        "Thank you for your message! An agent will respond shortly.",
        "I've noted your inquiry. Our team will get back to you soon!",
        "Great question! Let me connect you with one of our expert agents.",
        "Thanks for reaching out! We're here to help you find the perfect property."
      ];
      const randomResponse = responses[Math.floor(Math.random() * responses.length)];
      
      setMessages(prev => [...prev, {
        text: randomResponse,
        sender: 'Support Agent',
        timestamp: new Date(),
        isOwn: false
      }]);
    }, 2000);
  };

  const handleTyping = () => {
    if (socket && isConnected && user) {
      socket.emit('typing', {
        roomId: `user-${user._id}`,
        userId: user._id,
        isTyping: true
      });

      // Clear previous timeout
      if (typingTimeoutRef.current) {
        clearTimeout(typingTimeoutRef.current);
      }

      // Stop typing after 2 seconds
      typingTimeoutRef.current = setTimeout(() => {
        socket.emit('typing', {
          roomId: `user-${user._id}`,
          userId: user._id,
          isTyping: false
        });
      }, 2000);
    }
  };

  const quickReplies = [
    "I'm looking for a property",
    "Schedule a viewing",
    "Ask about financing",
    "Speak to an agent"
  ];

  const handleQuickReply = (reply) => {
    setInputMessage(reply);
  };

  return (
    <>
      {/* Chat Toggle Button */}
      <div className={`chat-toggle ${isOpen ? 'active' : ''}`} onClick={() => setIsOpen(!isOpen)}>
        <div className="toggle-icon">
          {isOpen ? '✕' : '💬'}
        </div>
        {!isOpen && (
          <div className="notification-badge">
            <span className="pulse-dot"></span>
          </div>
        )}
      </div>

      {/* Chat Window */}
      <div className={`chat-window ${isOpen ? 'open' : ''}`}>
        {/* Chat Header */}
        <div className="chat-header">
          <div className="chat-header-content">
            <div className="agent-avatar-chat">
              <span>👨‍💼</span>
              <div className={`status-dot ${isConnected ? 'online' : 'offline'}`}></div>
            </div>
            <div className="agent-info-chat">
              <h4>Real Estate Support</h4>
              <p className="status-text">{isConnected ? '🟢 Online' : '🔴 Offline'}</p>
            </div>
          </div>
          <button className="chat-close" onClick={() => setIsOpen(false)}>
            ✕
          </button>
        </div>

        {/* Messages Area */}
        <div className="chat-messages">
          {messages.map((msg, index) => (
            <div 
              key={index} 
              className={`message ${msg.isOwn ? 'own' : 'other'}`}
              style={{ animationDelay: `${index * 0.1}s` }}
            >
              {!msg.isOwn && (
                <div className="message-avatar">
                  {msg.sender === 'bot' ? '🤖' : '👨‍💼'}
                </div>
              )}
              <div className="message-content">
                {!msg.isOwn && <div className="message-sender">{msg.sender}</div>}
                <div className="message-bubble">
                  {msg.text}
                </div>
                <div className="message-time">
                  {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          ))}
          
          {isTyping && (
            <div className="message other">
              <div className="message-avatar">👨‍💼</div>
              <div className="typing-indicator">
                <span></span>
                <span></span>
                <span></span>
              </div>
            </div>
          )}
          
          <div ref={messagesEndRef} />
        </div>

        {/* Quick Replies */}
        {!isAuthenticated && (
          <div className="login-prompt">
            <p>Please login to chat with our agents</p>
          </div>
        )}

        {isAuthenticated && messages.length <= 2 && (
          <div className="quick-replies">
            {quickReplies.map((reply, index) => (
              <button
                key={index}
                className="quick-reply-btn"
                onClick={() => handleQuickReply(reply)}
              >
                {reply}
              </button>
            ))}
          </div>
        )}

        {/* Input Area */}
        <form className="chat-input-area" onSubmit={handleSendMessage}>
          <input
            type="text"
            value={inputMessage}
            onChange={(e) => {
              setInputMessage(e.target.value);
              handleTyping();
            }}
            placeholder={isAuthenticated ? "Type your message..." : "Login to send messages"}
            className="chat-input"
            disabled={!isAuthenticated}
          />
          <button 
            type="submit" 
            className="chat-send-btn"
            disabled={!inputMessage.trim() || !isAuthenticated}
          >
            <span className="send-icon">📤</span>
          </button>
        </form>
      </div>
    </>
  );
};

export default ChatBot;
